/** Get Sofascore CDN URL for a tournament/competition name, or null if not found. */
export function getSofascoreTournamentLogoUrl(name: string): string | null {
  const id = SOFASCORE_TOURNAMENT_IDS[name];
  if (id) return SOFA_URL(id);
  const catId = SOFASCORE_CATEGORY_IDS[name];
  if (catId) return SOFA_CAT_URL(catId);
  return null;
}

/** Get Sofascore category image URL for a country name. */
export function getSofascoreCategoryLogoUrl(categoryName: string): string | null {
  const catId = SOFASCORE_CATEGORY_IDS[categoryName];
  return catId ? SOFA_CAT_URL(catId) : null;
}
